using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// Build the IChatClient through the MEAI abstraction layer.
IChatClient chatClient = new OpenAI.Chat.ChatClient(modelId,
        new System.ClientModel.ApiKeyCredential(apiKey))
    .AsIChatClient();

// Shared state for the note-taking tool.
var notebook = new ResearchNotebook();

// A single HttpClient reused across searches.
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

// ── Tool definitions ────────────────────────────────────────────────
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up")] string query) =>
            WebSearchAsync(httpClient, query),
        "SearchWeb",
        "Search the web for information on a given query. Returns a JSON blob of results."),

    AIFunctionFactory.Create(
        ([Description("The content of the note to save")] string content) =>
            notebook.Save(content),
        "SaveNote",
        "Save a research note. Use this to record important findings as you go."),

    AIFunctionFactory.Create(
        () => notebook.GetAll(),
        "GetNotes",
        "Retrieve all research notes saved so far."),
};

// ── Agent setup ─────────────────────────────────────────────────────
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "Researches a topic using web search, takes notes, and summarizes findings.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = tools,
        },
    });

agent.Instructions = """
    You are a research agent. When the user gives you a topic:

    1. **Search** – call SearchWeb several times with varied queries to gather
       broad and specific information about the topic.
    2. **Take notes** – after each useful search, call SaveNote to record the
       key facts, statistics, or quotes you found.
    3. **Summarize** – once you have gathered enough material, call GetNotes to
       review everything, then write a well-structured summary with sections,
       bullet points, and source attributions where possible.

    Be thorough yet concise. Always prefer facts over speculation.
    """;

// ── Interactive loop ────────────────────────────────────────────────
Console.WriteLine("🔍  Research Agent Ready");
Console.WriteLine("    Enter a topic to research, or 'quit' to exit.\n");

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine();

    if (string.IsNullOrWhiteSpace(topic))
        continue;
    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\n📚  Researching: {topic}\n");

    notebook.Clear();

    var session = await agent.CreateSessionAsync(
        conversationId: Guid.NewGuid().ToString());

    var response = await agent.RunAsync(
        $"Research the following topic and provide a comprehensive summary: {topic}",
        session);

    Console.WriteLine(response.Text);
    Console.WriteLine();
}

// ── Web search helper ───────────────────────────────────────────────
static async Task<string> WebSearchAsync(HttpClient http, string query)
{
    var encoded = Uri.EscapeDataString(query);
    try
    {
        var json = await http.GetStringAsync(
            $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&t=ResearchAgent");

        if (string.IsNullOrWhiteSpace(json))
            return "No results found.";

        // Parse and extract the most useful fields.
        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        var parts = new List<string>();

        if (root.TryGetProperty("Abstract", out var abs) &&
            abs.GetString() is { Length: > 0 } abstractText)
        {
            parts.Add($"Abstract: {abstractText}");
        }

        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var item in topics.EnumerateArray().Take(8))
            {
                if (item.TryGetProperty("Text", out var text) &&
                    text.GetString() is { Length: > 0 } t)
                {
                    parts.Add($"- {t}");
                }
            }
        }

        return parts.Count > 0
            ? string.Join("\n", parts)
            : "No relevant results found for this query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

// ── Notebook (note-taking tool state) ───────────────────────────────
sealed class ResearchNotebook
{
    private readonly List<string> _notes = [];

    public string Save(string content)
    {
        _notes.Add(content);
        return $"Note #{_notes.Count} saved.";
    }

    public string GetAll()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n",
            _notes.Select((n, i) => $"--- Note #{i + 1} ---\n{n}"));
    }

    public void Clear() => _notes.Clear();
}

